const raw = $json.chatInput ?? '';
const sessionId = $json.sessionId ?? 'anonymous';

const item = {
  sessionId,
  chatInput: String(raw).trim(),
  normalized: String(raw).trim().toLowerCase().replace(/\s+/g, ' ')
};

return { json: item };

const staticData = $getWorkflowStaticData('global');
if (!staticData.users) staticData.users = {};

const sessionId = $json.sessionId;
const normalized = $json.normalized;
const now = Date.now();

const user = staticData.users[sessionId] || {
  timestamps: [],
  recentMessages: [],
  abuseScore: 0,
  blockedUntil: null
};

let blocked = false;
let reason = '';

if (user.blockedUntil && now < user.blockedUntil) {
  blocked = true;
  reason = 'cooldown_active';
} else {
  if (user.blockedUntil && now >= user.blockedUntil) {
    user.blockedUntil = null;
    user.abuseScore = 0;
  }

  // Rule 1: more than 10 messages in 30 seconds
  user.timestamps = user.timestamps.filter(t => now - t < 30000);
  user.timestamps.push(now);
  if (user.timestamps.length > 10) {
    blocked = true;
    reason = 'rate_limit';
    user.abuseScore += 1;
  }

  // Rule 2: same message repeated 3+ times in a row
  user.recentMessages.push(normalized);
  user.recentMessages = user.recentMessages.slice(-3);
  if (!blocked && user.recentMessages.length === 3 && new Set(user.recentMessages).size === 1) {
    blocked = true;
    reason = 'repeated_message';
    user.abuseScore += 1;
  }

  // Rule 3: abuseScore >= 5 triggers a 15-minute cooldown
  if (user.abuseScore >= 5) {
    user.blockedUntil = now + 15 * 60 * 1000;
    blocked = true;
    reason = 'cooldown_started';
  }
}

staticData.users[sessionId] = user;

const result = {
  sessionId,
  chatInput: $json.chatInput,
  normalized,
  blocked,
  reason,
  abuseScore: user.abuseScore
};

return { json: result };

const reply = {
  output: "You're sending messages too quickly. Please wait a few minutes and try again."
};
return { json: reply };

const staticData = $getWorkflowStaticData('global');
const sessionId = $json.sessionId;
const text = $json.normalized;

// Fast path: simple greetings get an instant canned reply (no LLM call)
const greetingPattern = /^(hi+|hello+|hey+|heya|yo|sup|good (morning|afternoon|evening)|salam|salaam|hola|bonjour)[\s!.,?]*$/;
if (greetingPattern.test(text)) {
  const result = {
    sessionId,
    chatInput: $json.chatInput,
    normalized: text,
    filtered: true,
    replyText: "Hi! I can help you book an appointment with Dr. Hakim. What date and time would you like? I'll also need your full name and phone number.",
    abuseScore: (staticData.users && staticData.users[sessionId]) ? staticData.users[sessionId].abuseScore : 0
  };
  return { json: result };
}

// A bare phone number is all digits — it must never be mistaken for math spam.
// Patients legitimately send just their number as their first or only message.
const digitsOnly = text.replace(/\D/g, '');
const isPhoneLike = /^[+\d][\d\s\-().]*$/.test(text) && digitsOnly.length >= 7 && digitsOnly.length <= 15;

// Math spam requires an actual operator BETWEEN digits (1+1, 2*5), not merely digits.
const looksLikeMath = !isPhoneLike
  && /^[\d\s+\-*/().=%^]+$/.test(text)
  && /\d\s*[+*/^%=]\s*\d|\d\s*-\s*\d/.test(text);

const patterns = [
  /ignore\s+(all\s+)?(previous|prior|above)\s+instructions/,
  /system\s+prompt/,
  /act\s+as\s+(chatgpt|gpt|dan|an?\s+ai)/,
  /you\s+are\s+now\s+/,
  /jailbreak|dan\s+mode|developer\s+mode/,
  /write\s+(python|javascript|java|c\+\+|code|a\s+script)/,
  /tell\s+me\s+a\s+joke/,
  /pretend\s+(to\s+be|you)/,
  /repeat\s+(your|the)\s+(instructions|prompt)/
];

const filtered = looksLikeMath || patterns.some(p => p.test(text));

if (filtered && staticData.users && staticData.users[sessionId]) {
  staticData.users[sessionId].abuseScore = (staticData.users[sessionId].abuseScore || 0) + 1;
}

const result = {
  sessionId,
  chatInput: $json.chatInput,
  normalized: text,
  filtered,
  replyText: "I can only help with dental appointments.",
  abuseScore: (staticData.users && staticData.users[sessionId]) ? staticData.users[sessionId].abuseScore : 0
};

return { json: result };

const reply = {
  output: $json.replyText || "I can only help with dental appointments."
};
return { json: reply };

