let intent = 'OUT_OF_SCOPE';

// If the classifier itself errored, fail OPEN to the agent rather than falsely rejecting a
// real patient. The rate limiter and regex filter have already run, and the agent carries its
// own guardrails, so this is the safe direction to fail.
const classifierFailed = !!($json.error || $json.errorMessage);

try {
  let content = $json.message && $json.message.content !== undefined ? $json.message.content : ($json.output !== undefined ? $json.output : $json);
  const obj = typeof content === 'string' ? JSON.parse(content) : content;
  if (obj && obj.intent) {
    intent = String(obj.intent).toUpperCase().trim();
  }
} catch (e) {
  intent = 'OUT_OF_SCOPE';
}

const source = $('Normalize Input').first().json;
const sessionId = source.sessionId;

const staticData = $getWorkflowStaticData('global');
if (!staticData.users) staticData.users = {};
const user = staticData.users[sessionId] || {};

const allowedIntents = ['BOOK_APPOINTMENT', 'RESCHEDULE', 'CANCEL', 'CLINIC_INFO', 'GREETING', 'FOLLOW_UP'];
let allowed = allowedIntents.includes(intent);

if (classifierFailed) {
  intent = 'CLASSIFIER_ERROR';
  allowed = true;
}

// Conversation-state override: if this session is mid-booking (the agent handled
// a message within the last 15 minutes), let an OUT_OF_SCOPE message through as a
// follow-up. The agent's own guardrails redirect genuinely off-topic messages.
// PROMPT_ATTACK is NEVER let through by this override.
const now = Date.now();
const inActiveFlow = user.lastAgentAt && (now - user.lastAgentAt < 15 * 60 * 1000);
if (!allowed && intent === 'OUT_OF_SCOPE' && inActiveFlow) {
  allowed = true;
  intent = 'FOLLOW_UP';
}

if (intent === 'PROMPT_ATTACK') {
  user.abuseScore = (user.abuseScore || 0) + 2;
}

if (allowed) {
  user.lastAgentAt = now;
}

staticData.users[sessionId] = user;

const result = {
  intent,
  allowed,
  sessionId,
  chatInput: source.chatInput
};

return { json: result };

const reply = {
  output: "I can only help with dental appointments."
};
return { json: reply };

const ERROR_MESSAGE = "There's an unexpected error, please call 09121231234";

let output;
try {
  output = $('AI Agent').first().json.output;
} catch (e) {
  output = null;
}

// Agent crashed, timed out, or returned nothing usable -> never leave the patient with a blank chat.
if (typeof output !== 'string' || output.trim() === '') {
  output = ERROR_MESSAGE;
}

const reply = { output };
return { json: reply };

// Deterministic office-hours gate. Input: a requested slot as "YYYY-MM-DD HH:mm" (Asia/Manila).
// Never trust the model to do weekday arithmetic.

const HOURS = {
  0: null,              // Sunday - closed
  1: [540, 1200],       // Mon 09:00-20:00
  2: [540, 1200],
  3: [540, 1200],
  4: [540, 1200],
  5: [540, 1200],       // Fri
  6: [540, 780]         // Sat 09:00-13:00
};
const DAY_NAMES = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const CONSULT = 60;   // minutes
const BUFFER  = 15;   // minutes between patients

const toHHMM = (m) => String(Math.floor(m/60)).padStart(2,'0') + ':' + String(m%60).padStart(2,'0');

const raw = String(query || '').trim();
const m = raw.match(/(\d{4})-(\d{1,2})-(\d{1,2})[T ](\d{1,2}):(\d{2})/);

if (!m) {
  const bad = { valid: false, reason: "Could not read the requested slot. Send it as 'YYYY-MM-DD HH:mm' in Asia/Manila time, e.g. 2026-07-18 17:00." };
  return JSON.stringify(bad);
}

const Y = Number(m[1]), Mo = Number(m[2]), D = Number(m[3]), H = Number(m[4]), Mi = Number(m[5]);
const dow = new Date(Date.UTC(Y, Mo - 1, D)).getUTCDay();
const dayName = DAY_NAMES[dow];
const startMin = H * 60 + Mi;
const window = HOURS[dow];

if (!window) {
  const closed = {
    valid: false,
    requested: raw,
    weekday: dayName,
    reason: dayName + " is closed. The clinic does not open on Sundays.",
    bookable_start_times: []
  };
  return JSON.stringify(closed);
}

const [openMin, closeMin] = window;

const slots = [];
for (let s = openMin; s + CONSULT <= closeMin; s += CONSULT + BUFFER) {
  slots.push(toHHMM(s));
}

const lastStart = closeMin - CONSULT;
let valid = true;
let reason = "Within office hours.";

if (startMin < openMin) {
  valid = false;
  reason = "The clinic opens at " + toHHMM(openMin) + " on " + dayName + ". " + toHHMM(startMin) + " is before opening.";
} else if (startMin + CONSULT > closeMin) {
  valid = false;
  reason = "The clinic closes at " + toHHMM(closeMin) + " on " + dayName +
           ", and a consultation lasts " + CONSULT + " minutes, so the latest possible start is " +
           toHHMM(lastStart) + ". " + toHHMM(startMin) + " is outside office hours.";
}

const result = {
  valid: valid,
  requested: raw,
  weekday: dayName,
  opens: toHHMM(openMin),
  closes: toHHMM(closeMin),
  latest_bookable_start: toHHMM(lastStart),
  reason: reason,
  bookable_start_times: slots
};
return JSON.stringify(result);
